  create policy "Enable read access for all users"
  on "public"."app_config"
  as permissive
  for select
  to public
using (true);



  create policy "누구나 배너를 조회할 수 있습니다."
  on "public"."banners"
  as permissive
  for select
  to public
using (true);



  create policy "Allow authenticated users to insert feedback"
  on "public"."feedbacks"
  as permissive
  for insert
  to authenticated
with check ((auth.uid() = user_id));



